sql:
SELECT 
    (SELECT AVG(average_income) FROM neighborhoods WHERE population > 1000000) -
    (SELECT AVG(average_income) FROM neighborhoods) AS income_difference;

SELECT AVG(n.average_income) 
FROM neighborhoods n
WHERE n.neighborhood_id IN (
    SELECT pt.neighborhood_id 
    FROM public_transport pt
) 
AND n.neighborhood_id NOT IN (
    SELECT r.neighborhood_id 
    FROM restaurants r
);

external_knowledge:
- "bustling American eateries" implies active American restaurants;
- "significant number" refers to the top 5 neighborhoods by count;
- "highest wealth" refers to the top 5 neighborhoods by average income;
- "among residents" refers to the average income of residents in each neighborhood.

sql:
SELECT neighborhood_name, average_income
FROM neighborhoods
ORDER BY average_income DESC;

SELECT neighborhood_name 
FROM neighborhoods 
ORDER BY neighborhood_name DESC;

SELECT category, COUNT(service_id) AS total_services
FROM services
GROUP BY category;

SELECT r.neighborhood_id, r.name AS restaurant_name, s.service_name
FROM restaurants r
JOIN services s ON r.type = s.service_name;
